extension Int {
    var isEven: Bool { self % 2 == 0 }
    func times(_ action: () -> Void) {
        for _ in 0..<self { action() }
    }
}

print(4.isEven) // true
3.times { print("hi") }

func maxOf<T: Comparable>(_ a: T, _ b: T) -> T {
    a > b ? a : b
}

print(maxOf(3, 9))       // 9
print(maxOf("a", "z"))  // z

struct Stack<Element> {
    private var items: [Element] = []
    mutating func push(_ x: Element) { items.append(x) }
    mutating func pop() -> Element? { items.popLast() }
}

enum Result {
    case success(data: String)
    case failure(code: Int)
}

let outcome = Result.failure(code: 404)

switch outcome {
case .success(let data):
    print("Got \(data)")
case .failure(let code):
    print("Failed with \(code)")
}

enum FileError: Error { case notFound, noPermission }

