func greet(_ name: String?) {
    guard let name, !name.isEmpty else {
        print("No name provided")
        return
    }
    // name is non-optional and non-empty here
    print("Hello, \(name)!")
}

@propertyWrapper
struct Clamped {
    private var value: Int
    let range: ClosedRange<Int>
    init(wrappedValue: Int, _ range: ClosedRange<Int>) {
        self.range = range
        self.value = min(max(wrappedValue, range.lowerBound), range.upperBound)
    }
    var wrappedValue: Int {
        get { value }
        set { value = min(max(newValue, range.lowerBound), range.upperBound) }
    }
}

struct Volume {
    @Clamped(0...10) var level = 5
}

struct Rectangle {
    var width: Double   // stored
    var height: Double  // stored

    var area: Double {  // computed (read-only)
        width * height
    }

    var diagonal: Double {
        get { (width * width + height * height).squareRoot() }
    }
}

var handlers: [() -> Void] = []

func store(_ handler: @escaping () -> Void) {
    handlers.append(handler) // escapes: stored for later
}

func runNow(_ action: () -> Void) {
    action() // non-escaping: runs before return
}

struct User: Codable {
    let id: Int
    let fullName: String

    enum CodingKeys: String, CodingKey {
        case id
        case fullName = "full_name"
    }
}

let json = "{\"id\":1,\"full_name\":\"Ada\"}".data(using: .utf8)!
let user = try JSONDecoder().decode(User.self, from: json)
print(user.fullName) // Ada

