public struct BankAccount {
    private var balance = 0.0            // hidden from everyone else
    public private(set) var owner: String // readable, writable only internally

    public init(owner: String) { self.owner = owner }
    public mutating func deposit(_ amount: Double) {
        balance += amount
    }
}

